"""money — internal shared library for monetary values.

ALL monetary arithmetic in this codebase lives in this package (see CLAUDE.md).
Amounts are integer cents — never floats. Modules outside this package compose
Money operations; they do not do arithmetic on raw cent values.

See README.md in this package for the API guide and CHANGELOG.md for history.
"""
from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class Money:
    cents: int

    def __post_init__(self) -> None:
        if not isinstance(self.cents, int):
            raise TypeError(f"Money is integer cents, got {type(self.cents).__name__}")

    @classmethod
    def from_cents(cls, cents: int) -> "Money":
        return cls(cents)

    def to_cents(self) -> int:
        return self.cents

    def __add__(self, other: "Money") -> "Money":
        return Money(self.cents + other.cents)

    def __sub__(self, other: "Money") -> "Money":
        return Money(self.cents - other.cents)

    def __mul__(self, k: int) -> "Money":
        if not isinstance(k, int):
            raise TypeError("Money can only be multiplied by an integer")
        return Money(self.cents * k)

    def allocate(self, weights: list[int]) -> list["Money"]:
        """Split this amount into integer-cent shares proportional to ``weights``.

        Weights are unitless non-negative integers (at least one positive).
        """
        if not weights:
            raise ValueError("weights must be non-empty")
        if any(w < 0 for w in weights):
            raise ValueError("weights must be non-negative")
        total = sum(weights)
        if total == 0:
            raise ValueError("at least one weight must be positive")
        # Largest-remainder allocation: floor every share, then distribute the
        # leftover cents to the largest fractional remainders. Shares always
        # sum back to exactly this amount (conservation invariant).
        shares = [self.cents * w // total for w in weights]
        leftover = self.cents - sum(shares)
        by_remainder = sorted(
            range(len(weights)),
            key=lambda i: ((self.cents * weights[i]) % total, -i),
            reverse=True,
        )
        for i in by_remainder[:leftover]:
            shares[i] += 1
        return [Money(c) for c in shares]

    def percent_of(self, bps: int) -> "Money":
        """Return the given basis-point fraction of this amount, rounded down.

        Intended for estimates and previews (fee hints at checkout, tax
        estimates), where a conservative floor is the desired behavior. Note
        that complementary ``percent_of`` results may not sum back to the
        whole amount — to split an amount into parts, use :meth:`allocate`.
        """
        if not isinstance(bps, int) or bps < 0:
            raise ValueError("bps must be a non-negative integer")
        return Money(self.cents * bps // 10_000)

    def __str__(self) -> str:
        sign = "-" if self.cents < 0 else ""
        c = abs(self.cents)
        return f"{sign}${c // 100}.{c % 100:02d}"

"""Core order domain objects."""
from __future__ import annotations

from dataclasses import dataclass, field

from libs.money import Money


@dataclass
class LineItem:
    sku: str
    vendor: str
    price: Money  # unit price
    qty: int = 1
    shipped: bool = False

    @property
    def line_total(self) -> Money:
        return self.price * self.qty


@dataclass
class Order:
    id: str
    items: list[LineItem] = field(default_factory=list)
    discount: Money = Money(0)  # order-level promo, applied to the whole order
    status: str = "fulfilled"  # "fulfilled" | "cancelled"
    charged_at: str = ""  # ISO date the customer was charged, e.g. "2026-04-17"

    @property
    def subtotal(self) -> Money:
        total = Money(0)
        for item in self.items:
            total = total + item.line_total
        return total

    @property
    def charged_total(self) -> Money:
        """What the customer was actually charged (post-discount)."""
        return self.subtotal - self.discount

"""Nightly finance exports.

Produces the CSV artifacts finance consumes for the quarterly close:

- charges.csv       — what each customer was actually charged (from the
                      payment processor's records; authoritative)
- refund_lines.csv  — per-line refund amounts recorded for cancelled orders
- payout_lines.csv  — platform fee + per-vendor payout amounts recorded for
                      fulfilled orders

The nightly job publishes these to `exports/` at the repo root. Running this
module manually writes to `./exports_preview/` so you don't clobber the
published artifacts.
"""
from __future__ import annotations

import csv
import sys
from pathlib import Path

from services.orders.payouts import platform_split, vendor_payouts
from services.orders.refunds import itemized_refund_amounts
from services.orders.repository import load_orders


def charge_rows(orders) -> list[dict]:
    return [
        {
            "order_id": o.id,
            "charged_at": o.charged_at,
            "status": o.status,
            "charged_cents": o.charged_total.to_cents(),
        }
        for o in orders
    ]


def refund_line_rows(orders) -> list[dict]:
    rows = []
    for order in orders:
        if order.status != "cancelled":
            continue
        for item, amount in zip(order.items, itemized_refund_amounts(order)):
            rows.append(
                {"order_id": order.id, "sku": item.sku, "amount_cents": amount.to_cents()}
            )
    return rows


def payout_line_rows(orders) -> list[dict]:
    rows = []
    for order in orders:
        if order.status != "fulfilled":
            continue
        _, platform_fee = platform_split(order)
        rows.append(
            {"order_id": order.id, "payee": "platform", "amount_cents": platform_fee.to_cents()}
        )
        for vendor, share in vendor_payouts(order).items():
            rows.append(
                {"order_id": order.id, "payee": vendor, "amount_cents": share.to_cents()}
            )
    return rows


def write_all(out_dir: Path) -> None:
    out_dir.mkdir(parents=True, exist_ok=True)
    orders = load_orders()
    for name, rows in (
        ("charges.csv", charge_rows(orders)),
        ("refund_lines.csv", refund_line_rows(orders)),
        ("payout_lines.csv", payout_line_rows(orders)),
    ):
        with (out_dir / name).open("w", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=list(rows[0].keys()))
            writer.writeheader()
            writer.writerows(rows)


if __name__ == "__main__":
    target = Path(sys.argv[1]) if len(sys.argv) > 1 else Path("exports_preview")
    write_all(target)
    print(f"wrote exports to {target}/")

