    orders = load_orders()
    cancelled = {o.id for o in orders if o.status == "cancelled"}
    rows = refund_line_rows(orders)
    assert rows and {r["order_id"] for r in rows} == cancelled


def test_payout_lines_only_for_fulfilled_orders():
    orders = load_orders()
    fulfilled = {o.id for o in orders if o.status == "fulfilled"}
    rows = payout_line_rows(orders)
    assert rows and {r["order_id"] for r in rows} == fulfilled
    assert any(r["payee"] == "platform" for r in rows)
